**Rust Implementation**:
```rust
use bubbletea::{Model, Program, Cmd};
use std::io;

struct Counter {
    count: i32,
}

enum Msg {
    Increment,
    Decrement,
    Quit,
}

impl Model for Counter {
    type Message = Msg;

    fn init(&self) -> Cmd<Self::Message> {
        Cmd::none()
    }

    fn update(&mut self, msg: Self::Message) -> Cmd<Self::Message> {
        match msg {
            Msg::Increment => self.count += 1,
            Msg::Decrement => self.count -= 1,
            Msg::Quit => return Cmd::quit(),
        }
        Cmd::none()
    }

    fn view(&self) -> String {
        format!(
            "Count: {}\n\nPress +/- to change, q to quit",
            self.count
        )
    }
}

fn main() -> anyhow::Result<()> {
    let model = Counter { count: 0 };
    Program::new(model).run()?;
    Ok(())
}
```

