use huh::{Form, Text, Select, MultiSelect, Confirm};

fn main() -> anyhow::Result<()> {
    let form = Form::new()
        .title("User Registration")
        .field(
            Text::new("name")
                .title("Full Name")
                .placeholder("Enter your name")
                .validate(|s| {
                    if s.len() < 2 {
                        Err("Name must be at least 2 characters")
                    } else {
                        Ok(())
                    }
                })
        )
        .field(
            Text::new("email")
                .title("Email Address")
                .validate(|s| {
                    if s.contains('@') {
                        Ok(())
                    } else {
                        Err("Invalid email format")
                    }
                })
        )
        .field(
            Select::new("country")
                .title("Country")
                .options(vec!["USA", "Canada", "UK", "Germany", "Other"])
        )
        .confirm("Submit this form?");

    let result = form.run()?;
    println!("Submitted: {:?}", result);
    Ok(())
}
```

