#[test]
fn test_no_flash_on_theme_switch() {
    // Simulate rapid theme switching
    let context = Arc::new(ThemeContext::new(Theme::from_preset(Preset::Dark)));
    let style = Style::themed(&context).foreground_slot(ColorSlot::Text);

    let mut outputs = Vec::new();

    for i in 0..20 {
        let preset = if i % 2 == 0 { Preset::Dark } else { Preset::Light };
        context.set_theme(Theme::from_preset(preset));
        outputs.push(style.render("Content"));
    }

    // All outputs should be valid (no corrupted ANSI)
    for (i, output) in outputs.iter().enumerate() {
        assert!(
            !output.contains("\x1b\x1b"), // Double escape = corruption
            "Output {} has corrupted ANSI",
            i
        );
    }
}

