+/// Checks if a path is a markdown file.
+fn is_markdown_file(path: &Path) -> bool {
+    path.extension()
+        .and_then(OsStr::to_str)
+        .map(|ext| matches!(ext.to_lowercase().as_str(), "md" | "markdown" | "mdown" | "mkd"))
+        .unwrap_or(false)
+}
